DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260708071632_InitialPostgresCreate') THEN
    CREATE TABLE "Courses" (
        "courseId" integer GENERATED BY DEFAULT AS IDENTITY,
        "hashCode" character varying(128),
        "courseName" character varying(255) NOT NULL,
        description text,
        "subjectId" integer,
        "instructorId" integer,
        price numeric(18,2),
        "createdAt" timestamp without time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
        "updatedAt" timestamp without time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
        CONSTRAINT "PK_Courses" PRIMARY KEY ("courseId"),
        CONSTRAINT "FK_Courses_Instructors_instructorId" FOREIGN KEY ("instructorId") REFERENCES "Instructors" ("Id") ON DELETE SET NULL,
        CONSTRAINT "FK_Courses_Subjects_subjectId" FOREIGN KEY ("subjectId") REFERENCES "Subjects" ("subjectId") ON DELETE SET NULL
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260708071632_InitialPostgresCreate') THEN
    CREATE TABLE "CourseRegistrations" (
        "registrationId" integer GENERATED BY DEFAULT AS IDENTITY,
        "hashCode" character varying(128),
        "fullName" character varying(255) NOT NULL,
        email character varying(255),
        phone character varying(20) NOT NULL,
        "courseId" integer NOT NULL,
        status character varying(50) NOT NULL DEFAULT 'Mới',
        "createdAt" timestamp without time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
        CONSTRAINT "PK_CourseRegistrations" PRIMARY KEY ("registrationId"),
        CONSTRAINT "FK_Registration_Course" FOREIGN KEY ("courseId") REFERENCES "Courses" ("courseId") ON DELETE CASCADE
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260708071632_InitialPostgresCreate') THEN
    CREATE TABLE "TeachingClasses" (
        "classId" integer GENERATED BY DEFAULT AS IDENTITY,
        "hashCode" character varying(128),
        "className" character varying(255) NOT NULL,
        "courseId" integer NOT NULL,
        "subjectId" integer,
        "instructorId" integer,
        "startDate" timestamp without time zone NOT NULL,
        "endDate" timestamp without time zone NOT NULL,
        status character varying(50) NOT NULL DEFAULT 'Active',
        note character varying(500),
        "createdAt" timestamp without time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
        "updatedAt" timestamp without time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
        CONSTRAINT "PK_TeachingClasses" PRIMARY KEY ("classId"),
        CONSTRAINT "FK_TeachingClasses_Courses_courseId" FOREIGN KEY ("courseId") REFERENCES "Courses" ("courseId") ON DELETE CASCADE,
        CONSTRAINT "FK_TeachingClasses_Instructors_instructorId" FOREIGN KEY ("instructorId") REFERENCES "Instructors" ("Id") ON DELETE SET NULL,
        CONSTRAINT "FK_TeachingClasses_Subjects_subjectId" FOREIGN KEY ("subjectId") REFERENCES "Subjects" ("subjectId") ON DELETE SET NULL
    );
    END IF;
END $EF$;

