DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260708071632_InitialPostgresCreate') THEN
    PERFORM setval(
        pg_get_serial_sequence('"Subjects"', 'subjectId'),
        GREATEST(
            (SELECT MAX("subjectId") FROM "Subjects") + 1,
            nextval(pg_get_serial_sequence('"Subjects"', 'subjectId'))),
        false);
    END IF;
END $EF$;

